// ─── Internal: DB lookup cache ───────────────────────────────────
// Convert PowerCurveEntry → PowerCurvePoint[] lazily and cache result

const curvePointsCache: Map<string, PowerCurvePoint[]> = new Map();

function dbKey(manufacturer: string, model: string): string {
    return `${manufacturer}|${model}`;
}

function entryToPoints(entry: PowerCurveEntry): PowerCurvePoint[] {
    const points: PowerCurvePoint[] = [];
    for (let i = 0; i < entry.p.length; i++) {
        points.push({ windSpeed: i * 0.5, power: entry.p[i] });
    }
    return points;
}

function lookupEntry(manufacturer: string, model: string): PowerCurveEntry | null {
    return POWER_CURVE_DB[dbKey(manufacturer, model)] ?? null;
}

// ─── Public API ──────────────────────────────────────────────────

/**
 * Check whether a model-specific power curve exists in the database.
 */
export function hasPowerCurve(manufacturer: string, model: string): boolean {
    return dbKey(manufacturer, model) in POWER_CURVE_DB;
}

/**
 * Get the rated (max) power for a known turbine model, or null if unknown.
 */
export function getRatedPower(manufacturer: string, model: string): number | null {
    const entry = lookupEntry(manufacturer, model);
    return entry ? entry.r : null;
}

/**
 * Get the cut-out wind speed for a known turbine model.
 * Falls back to 25.0 m/s if the model is unknown.
 */
export function getCutOutSpeed(manufacturer: string, model: string): number {
    const entry = lookupEntry(manufacturer, model);
    return entry ? entry.c : 25.0;
}

/**
 * Get the power curve for a specific turbine model.
 * 
 * If a model-specific curve exists in the database, returns it directly.
 * Otherwise, returns the Vestas V112 reference curve scaled to `ratedCapacityKW`
 * (if provided) or unscaled.
 * 
 * @param manufacturer  Turbine manufacturer name
 * @param model         Turbine model name
 * @param ratedCapacityKW  Optional rated capacity for generic scaling
 * @returns Array of PowerCurvePoint
 */
export function getPowerCurve(
    manufacturer: string, 
    model: string, 
    ratedCapacityKW?: number
): PowerCurvePoint[] {
    const key = dbKey(manufacturer, model);

    // Check the points cache
    if (curvePointsCache.has(key)) {
        return curvePointsCache.get(key)!;
    }

    // Check the DB
    const entry = lookupEntry(manufacturer, model);
    if (entry) {
        const points = entryToPoints(entry);
        curvePointsCache.set(key, points);
        return points;
    }

    // No specific curve → scale V112 to rated capacity
    if (ratedCapacityKW && ratedCapacityKW !== VESTAS_V112_SPECS.ratedPower) {
        const scale = ratedCapacityKW / VESTAS_V112_SPECS.ratedPower;
        const scaled = VESTAS_V112_POWER_CURVE.map(pt => ({
            windSpeed: pt.windSpeed,
            power: Math.round(pt.power * scale)
        }));
        // Cache with capacity-specific key so different capacities don't collide
        const cacheKey = `${key}@${ratedCapacityKW}`;
        curvePointsCache.set(cacheKey, scaled);
        return scaled;
    }

    return VESTAS_V112_POWER_CURVE;
}

/**
 * Interpolate power output from a power curve for a given wind speed.
 * Handles both DB-format (0.5 m/s steps) and arbitrary point arrays.
 */
export function interpolatePowerCurve(windSpeed: number, powerCurve: PowerCurvePoint[]): number {
    if (windSpeed < 0) return 0;
    if (windSpeed > 29.5) return 0;

    const lowerIndex = Math.floor(windSpeed * 2);
    const upperIndex = Math.min(lowerIndex + 1, powerCurve.length - 1);

    if (lowerIndex >= powerCurve.length - 1) {
        return powerCurve[powerCurve.length - 1].power;
    }

    const lowerPoint = powerCurve[lowerIndex];
    const upperPoint = powerCurve[upperIndex];
    const denom = upperPoint.windSpeed - lowerPoint.windSpeed;
    if (denom === 0) return lowerPoint.power;

    const fraction = (windSpeed - lowerPoint.windSpeed) / denom;
    return Math.round(lowerPoint.power + fraction * (upperPoint.power - lowerPoint.power));
}

/**
 * Fast power interpolation directly from a DB entry's compact array.
 * Avoids PowerCurvePoint[] allocation; used in hot paths.
 */
export function interpolateFromEntry(windSpeed: number, entry: PowerCurveEntry): number {
    if (windSpeed < 0 || windSpeed > 30) return 0;
    const idx = windSpeed * 2;          // 0.5 m/s steps
    const lo = Math.floor(idx);
    const hi = Math.min(lo + 1, 60);
    if (lo >= 60) return entry.p[60];
    const frac = idx - lo;
    return Math.round(entry.p[lo] + frac * (entry.p[hi] - entry.p[lo]));
}

/**
 * Get power output for the reference 3 MW turbine (Vestas V112).
 */
export function getPowerOutput(windSpeed: number): number {
    return interpolatePowerCurve(windSpeed, VESTAS_V112_POWER_CURVE);
}

/**
 * Get power output for a specific turbine type at a given wind speed.
 * 
 * If a model-specific curve exists, interpolates from it directly.
 * Otherwise, scales the V112 reference curve by the capacity ratio.
 */
export function getTurbinePowerOutput(
    windSpeed: number,
    manufacturer: string,
    model: string,
    ratedCapacityKW: number
): number {
    // Try the DB first (fast path)
    const entry = lookupEntry(manufacturer, model);
    if (entry) {
        return interpolateFromEntry(windSpeed, entry);
    }

    // Fallback: scale V112 reference
    const referencePower = interpolatePowerCurve(windSpeed, VESTAS_V112_POWER_CURVE);
    const scaleFactor = ratedCapacityKW / VESTAS_V112_SPECS.ratedPower;
    return Math.round(referencePower * scaleFactor);
}

/**
 * Calculate capacity factor.
 */
export function getCapacityFactor(power: number, ratedPower: number = VESTAS_V112_SPECS.ratedPower): number {
    return (power / ratedPower) * 100;
}

/**
 * Get operational status based on wind speed and (optional) model-specific cut-out.
 */
export function getOperationalStatus(
    windSpeed: number,
    manufacturer?: string,
    model?: string
): string {
    const cutOut = (manufacturer && model) ? getCutOutSpeed(manufacturer, model) : 25.0;
    const cutIn = 3.0;
    const rated = cutOut - 1; // approximate rated region

    if (windSpeed < cutIn) {
        return 'Below cut-in speed';
    } else if (windSpeed > cutOut) {
        return 'Above cut-out (shutdown)';
    } else if (windSpeed >= rated) {
        return 'At rated power';
    } else {
        return 'Operating';
    }
}

/**
 * Generate SVG path data for a power curve chart.
 */
export function generatePowerCurvePath(
    powerCurve: PowerCurvePoint[],
    maxPowerKW: number,
    chartWidth: number = 250,
    chartHeight: number = 110,
    xOffset: number = 40,
    yOffset: number = 10
): string {
    let path = 'M';
    powerCurve.forEach((point, i) => {
        const x = xOffset + (point.windSpeed / 30) * chartWidth;
        const y = (yOffset + chartHeight) - (point.power / maxPowerKW) * chartHeight;
        path += `${i === 0 ? '' : ' L'}${x.toFixed(1)} ${y.toFixed(1)}`;
    });
    return path;
}
